package main

// SF=1 answer validation. The reference results ship as answers_sf1.json
// (copied verbatim from v5, generated by cmd/tpch-answers from the upstream
// .ans files). At SF=1 on postgres the loaded dataset is the canonical dbgen
// dataset, so each of the 22 queries must reproduce its reference result set
// within the TPC-H §2.1.3.5 numeric tolerance (±1% or ±100, whichever is
// looser; everything else compares as an exact string).
//
// The validator is its own Once step (validate_answers), Skippable and gated
// by If(SF==1 && pg && VALIDATE). It shares the workload's pinned params and
// SQL corpus; failures mark the step Failed so the run halts after the full
// pass (D10: emit a fail-rooted error so every statement still executes first).

import (
	_ "embed"
	"encoding/json"
	"fmt"
	"log"
	"strconv"
	"strings"

	"github.com/stroppy-io/stroppy/next/bench"
	"github.com/stroppy-io/stroppy/next/driver"
	"github.com/stroppy-io/stroppy/next/sqlfile"
)

//go:embed answers_sf1.json
var answersSF1 []byte

// answerBlock is one query's reference result set.
type answerBlock struct {
	Columns []string   `json:"columns"`
	Rows    [][]string `json:"rows"`
}

// answersFile is the top-level shape of answers_sf1.json.
type answersFile struct {
	Version string                  `json:"version"`
	Source  string                  `json:"source"`
	Answers map[string]answerBlock `json:"answers"`
}

// loadAnswers parses the embedded reference answers.
func loadAnswers() (map[string]answerBlock, error) {
	var af answersFile
	if err := json.Unmarshal(answersSF1, &af); err != nil {
		return nil, fmt.Errorf("tpch: parse answers_sf1.json: %w", err)
	}
	return af.Answers, nil
}

// validateAnswers runs q1..q22 against the loaded data and compares each result
// set to its SF=1 reference, returning a fail-rooted error naming every
// mismatching query so the step is marked Failed after the full pass.
func validateAnswers(file *sqlfile.File) bench.Handler {
	return bench.FuncOnce(func(vu *bench.VU) error {
		want, err := loadAnswers()
		if err != nil {
			return err
		}
		conn, err := vu.Conn()
		if err != nil {
			return err
		}
		var bad []string
		for _, name := range queryNames {
			ref, ok := want[name]
			if !ok {
				log.Printf("[tpch_validate] %s: no reference answer", name)
				continue
			}
			q, ok := file.Query(name, "body")
			if !ok {
				return fmt.Errorf("tpch: query %s/body missing", name)
			}
			stmt, err := vu.Prepare(q)
			if err != nil {
				return fmt.Errorf("tpch: prepare %s: %w", name, err)
			}
			args := stmt.Bind()
			for _, p := range queryParams[name] {
				p.set(args)
			}
			rows, err := conn.QueryWithArgs(vu.Ctx(), stmt, args)
			if err != nil {
				return fmt.Errorf("tpch: %s: %w", name, err)
			}
			got, err := drainStrings(rows)
			if err != nil {
				return fmt.Errorf("tpch: %s: %w", name, err)
			}
			if deltas := compareRows(got, ref.Rows); len(deltas) > 0 {
				bad = append(bad, name)
				preview := deltas[0]
				if len(deltas) > 1 {
					preview = fmt.Sprintf("%s (+%d more)", preview, len(deltas)-1)
				}
				log.Printf("[tpch_validate] %s: DIFF rows=%d/%d  %s", name, len(got), len(ref.Rows), preview)
			} else {
				log.Printf("[tpch_validate] %s: OK rows=%d", name, len(got))
			}
		}
		if len(bad) > 0 {
			return bench.Fail(fmt.Errorf("tpch: %d query/queries mismatched the SF=1 reference: %s", len(bad), strings.Join(bad, ",")))
		}
		log.Printf("[tpch_validate] all 22 queries match the SF=1 reference")
		return nil
	})
}

// drainStrings reads every row of every column as a trimmed string for
// comparison. Validation is a cold one-shot pass, so the per-row allocation is
// fine (not the measured hot path).
func drainStrings(rows driver.Rows) ([][]string, error) {
	defer rows.Close()
	var out [][]string
	ncols := -1
	for rows.Next() {
		if ncols < 0 {
			// RawValues length is the column count; only valid after Next.
			ncols = len(rows.RawValues())
		}
		row := make([]string, ncols)
		for c := 0; c < ncols; c++ {
			s, _ := rows.ScanString(c)
			row[c] = strings.TrimSpace(s)
		}
		out = append(out, row)
	}
	return out, rows.Err()
}

const (
	tolRel = 0.01 // ±1%
	tolAbs = 100  // ±100 (currency units)
)

// compareRows returns one delta string per the first mismatch in each row, up to
// a small bound. A row count mismatch alone is a mismatch.
func compareRows(got, want [][]string) []string {
	var deltas []string
	const maxDeltas = 8
	n := len(got)
	if len(want) > n {
		n = len(want)
	}
	for i := 0; i < n && len(deltas) < maxDeltas; i++ {
		if i >= len(got) {
			deltas = append(deltas, fmt.Sprintf("row %d: missing, want=%v", i, want[i]))
			continue
		}
		if i >= len(want) {
			deltas = append(deltas, fmt.Sprintf("row %d: extra, got=%v", i, got[i]))
			continue
		}
		ncols := len(got[i])
		if len(want[i]) > ncols {
			ncols = len(want[i])
		}
		for c := 0; c < ncols && len(deltas) < maxDeltas; c++ {
			g, w := cell(got[i], c), cell(want[i], c)
			if !cellsMatch(g, w) {
				deltas = append(deltas, fmt.Sprintf("row %d col %d: got=%s want=%s", i, c, g, w))
			}
		}
	}
	return deltas
}

func cell(row []string, c int) string {
	if c < len(row) {
		return row[c]
	}
	return ""
}

// cellsMatch compares two cells: exact string first, then numeric tolerance
// when both parse as floats (TPC-H §2.1.3.5: ±1% or ±100).
func cellsMatch(got, want string) bool {
	if got == want {
		return true
	}
	g, err1 := strconv.ParseFloat(got, 64)
	w, err2 := strconv.ParseFloat(want, 64)
	if err1 != nil || err2 != nil {
		return false
	}
	delta := g - w
	if delta < 0 {
		delta = -delta
	}
	if delta <= tolAbs {
		return true
	}
	denom := w
	if denom < 0 {
		denom = -denom
	}
	if denom < 1 {
		denom = 1
	}
	return delta/denom <= tolRel
}
